import { useEffect } from 'react';
import { useAliveController } from 'react-activation';
import { useRefFunction } from '../../../hooks';
import { CachedTabEvent, TAB_EVENT_TYPE, TabEventClient } from '../CachedTabs';

const checkTabPathStarts = (starts: string, path?: string | string[]) => {
    if (!path) {
        return false;
    }
    if (Array.isArray(path)) {
        return path.some(p => p.startsWith(starts));
    }
    return path.startsWith(starts);
}

export const useTabsClientInit = (appCode: string) => {
    const { drop, refresh, getCachingNodes } = useAliveController();
    const dropOther = async (key: string) => {
        const nodes = getCachingNodes?.() ?? [];
        const needDropedNodes = nodes.filter(node => node.cacheKey !== key);
        const dropRes = await Promise.all(needDropedNodes?.map(node => drop?.(node.cacheKey)) ?? []);
        if (dropRes.some(res => !res)) {
            console.error('Drop Error, ', dropRes, needDropedNodes);
        }
    };

    const onTabEvent = useRefFunction((event: CachedTabEvent) => {
        const { type, data } = event;
        if (!checkTabPathStarts(`/${appCode}`, data?.tab?.path)) {
            return;
        }
        if (type === TAB_EVENT_TYPE.CLOSE) {
            drop?.(data?.key!);
        } else if (type === TAB_EVENT_TYPE.REFRESH) {
            refresh?.(data.key);
        } else if (type === TAB_EVENT_TYPE.CLOSE_OTHER) {
            dropOther(data.key);
        }
    });

    useEffect(() => {
        TabEventClient?.on(onTabEvent);

        return () => {
            TabEventClient?.off(onTabEvent);
        };
    }, []);
};
